prices_input = input().split(',')
prices = []
for price in prices_input:
    prices.append(int(price))

K = int(input())
pairs = []

for i in range(len(prices)):
    for j in range(i + 1, len(prices)):
        if prices[i] + prices[j] == K:
            smaller = min(prices[i], prices[j])
            larger = max(prices[i], prices[j])
            pair = (smaller, larger)
            if pair not in pairs:
                pairs.append(pair)

pairs.sort()
for pair in pairs:
    print(pair)
